import { consume } from '@lit/context'
import { $LitElement } from '@mixins/index'
import { delayContext } from '@schmancy/delay'
import hashContent from '@schmancy/utils/hashContent'
import { intersection$ } from '@schmancy/utils/intersection'
import { css, html, TemplateResult } from 'lit'
import { customElement, property, query, queryAssignedElements, queryAssignedNodes } from 'lit/decorators.js'
// TypeIt is loaded lazily on first render — see ADR 0014 in the parent
// monorepo. The static import was replaced with a type-only import plus a
// memoised dynamic loader so the ~15 KB gzipped vendor chunk stays out of
// the agent bundle's first paint for pages that don't render a typewriter.
import type { Options as TypeItOptions } from 'typeit'
type TypeItCtor = typeof import('typeit').default
type TypeItInstance = InstanceType<TypeItCtor>

let typeItPromise: Promise<TypeItCtor> | null = null
function loadTypeIt(): Promise<TypeItCtor> {
	if (typeItPromise) return typeItPromise
	typeItPromise = import('typeit').then(m => m.default)
	return typeItPromise
}

/**
 * Typewriter effect — animates text typing/deletion with a cursor. Wraps the TypeIt library, lazy-loaded on first render.
 *
 * @element schmancy-typewriter
 * @summary Drop string content as the default slot or use `<p>` / `<span>` with `cycle="A|B|C"` attribute children for cycling phrases. Set `loop` for infinite cycling, `once` to remember completion across sessions via sessionStorage.
 * @example
 * <schmancy-typewriter speed="35" cursor-char="|">
 *   Hello, world.
 * </schmancy-typewriter>
 * @platform span - Animated text container. Degrades to its raw text content if the tag never registers — animation is lost but content stays visible.
 * @fires typeit-complete - When the animation finishes typing all content. Fires after the final `afterComplete` callback in the underlying TypeIt instance.
 */
@customElement('schmancy-typewriter')
export class TypewriterElement extends $LitElement(css`
	:host {
		display: inline-block;
	}

	#typewriter {
		position: relative;
	}

	/* Enhanced cursor with glow effect */
	#typewriter :global(.ti-cursor) {
		animation: cursor-pulse 1.2s cubic-bezier(0.4, 0, 0.2, 1) infinite;
		color: currentColor;
		filter: drop-shadow(0 0 8px currentColor);
	}

	@keyframes cursor-pulse {
		0%, 100% {
			opacity: 1;
			transform: scale(1);
		}
		50% {
			opacity: 0.3;
			transform: scale(0.95);
		}
	}

	/* Character entrance animation */
	#typewriter :global(.ti-container *) {
		animation: char-entrance 0.3s cubic-bezier(0.34, 1.56, 0.64, 1) backwards;
	}

	@keyframes char-entrance {
		0% {
			opacity: 0;
			transform: scale(0.3) translateY(10px);
			filter: blur(4px);
		}
		50% {
			opacity: 0.8;
			transform: scale(1.1) translateY(-2px);
		}
		100% {
			opacity: 1;
			transform: scale(1) translateY(0);
			filter: blur(0);
		}
	}

	/* Subtle character wobble on appear */
	#typewriter :global(.ti-container *:nth-child(odd)) {
		animation: char-entrance 0.3s cubic-bezier(0.34, 1.56, 0.64, 1) backwards,
		           char-wobble 0.4s cubic-bezier(0.34, 1.56, 0.64, 1) 0.15s backwards;
	}

	@keyframes char-wobble {
		0%, 100% {
			transform: rotate(0deg);
		}
		25% {
			transform: rotate(2deg);
		}
		75% {
			transform: rotate(-2deg);
		}
	}

	/* Deletion animation - fade out and scale down */
	#typewriter :global(.ti-container .deleting) {
		animation: char-delete 0.2s cubic-bezier(0.4, 0, 1, 1) forwards;
	}

	@keyframes char-delete {
		0% {
			opacity: 1;
			transform: scale(1);
			filter: blur(0);
		}
		50% {
			opacity: 0.5;
			transform: scale(0.8) translateY(-3px);
		}
		100% {
			opacity: 0;
			transform: scale(0.4) translateY(-8px);
			filter: blur(3px);
		}
	}

	/* Gradient text effect on typed text */
	#typewriter :global(.ti-container) {
		background: linear-gradient(
			90deg,
			currentColor 0%,
			currentColor 70%,
			transparent 100%
		);
		-webkit-background-clip: text;
		background-clip: text;
		animation: gradient-shift 3s ease-in-out infinite;
	}

	@keyframes gradient-shift {
		0%, 100% {
			filter: brightness(1) saturate(1);
		}
		50% {
			filter: brightness(1.15) saturate(1.2);
		}
	}

	/* Smooth transitions for all text */
	#typewriter * {
		transition: opacity 0.15s ease-out, transform 0.15s cubic-bezier(0.34, 1.56, 0.64, 1);
	}
`) {
	/**
	 * Typing speed in milliseconds per character.
	 */
	@property({ type: Number })
	speed: number = 35

	/**
	 * Delay before typing starts (ms).
	 */
	@consume({ context: delayContext, subscribe: true })
	@property({ type: Number })
	delay: number = 0

	/**
	 * Automatically start typing on initialization.
	 */
	@property({ type: Boolean })
	autoStart: boolean = true

	/**
	 * The cursor character.
	 */
	@property({ type: String })
	cursorChar: string = ''

	/**
	 * Typing speed for deletions (ms per character).
	 */
	@property({ type: Number })
	deleteSpeed: number = 20

	/**
	 * Only animate once per session.
	 */
	@property({ type: Boolean }) once = true

	/**
	 * Loop the animation infinitely (overrides once).
	 */
	@property({ type: Boolean }) loop = false

	/**
	 * Default pause duration for cycling (ms).
	 */
	@property({ type: Number }) cyclePause = 1500
	/**
	 * TypeIt instance. Populated after `loadTypeIt()` resolves inside
	 * `_startTyping()` — null until then, which is correct for a cold start
	 * where the vendor chunk hasn't loaded yet.
	 */
	private typeItInstance: TypeItInstance | null = null

	/**
	 * Reference to the typewriter container.
	 */
	@query('#typewriter')
	private typewriterContainer!: HTMLElement

	@queryAssignedNodes({
		flatten: true,
	})
	private _getSlottedNodes!: Node[]

	@queryAssignedElements({
		flatten: true,
	})
	private _getSlottedElements!: HTMLElement[]
	/**
	 * Lifecycle method called when the component is disconnected from the DOM.
	 * Ensures that TypeIt instances are properly cleaned up.
	 */

	private sessionKey = ''
	disconnectedCallback() {
		super.disconnectedCallback()
		this._destroyTypeIt()
	}

	/**
	 * Initializes the TypeIt instance with the provided slotted content.
	 * Async because TypeIt itself is lazy-loaded on first render.
	 */
	private async _startTyping() {
		// Destroy any existing TypeIt instance
		this._destroyTypeIt()

		this.sessionKey = this.generateSessionKey()

		if (this.once && sessionStorage.getItem(this.sessionKey) === 'true') {
			// Skip delay and render immediately if once is set and already rendered
			this.shadowRoot?.querySelector('slot')?.removeAttribute('hidden')
			return
		}

		if (!this.typewriterContainer) {
			console.warn('Typewriter container not found.')
			return
		}

		// Configure TypeIt options
		const typeItOptions: TypeItOptions = {
			speed: this.speed,
			startDelay: this.delay,
			cursor: !!this.cursorChar,
			cursorChar: this.cursorChar,
			deleteSpeed: this.deleteSpeed,
			loop: this.loop,
			afterComplete: () => {
				if (this.once && !this.loop) {
					try {
						sessionStorage.setItem(this.sessionKey, 'true')
					} catch (error) {
						console.error('Error saving to session storage:', error)
					}
				}
				// Dispatch the custom event
				this.dispatchEvent(new CustomEvent('typeit-complete', { bubbles: true, composed: true }))

				// Hide the cursor (unless looping)
				if (!this.loop) {
					this.typewriterContainer.style.setProperty('--ti-cursor-display', 'none')
				}
			},
		}

		// Load TypeIt lazily on first call (module-scope memoised promise).
		const TypeIt = await loadTypeIt()
		// Bail if we were disconnected during the load — avoids attaching to
		// a detached host.
		if (!this.isConnected) return

		// Initialize TypeIt
		this.typeItInstance = new TypeIt(this.typewriterContainer, typeItOptions)

		// Process slotted content as actions
		const slottedNodes = this._getSlottedNodes
		slottedNodes.forEach(node => {
			if (node.nodeType === Node.TEXT_NODE) {
				// Handle plain text - skip whitespace-only text nodes
				const textContent = node.textContent || ''
				if (textContent.trim()) {
					this.typeItInstance?.type(textContent)
				}
			} else if (node instanceof HTMLElement) {
				// Handle custom element
				this._processCustomElement(node)
			}
		})

		// Start the typing animation if autoStart is enabled
		// use rxjs to detect once we are in the view port
		intersection$(this.shadowRoot?.host as Element).subscribe(() => {
			// alert('in view')
			this.typeItInstance?.go()
		})
		// Start the typing animation if autoStart is enabled
	}

	private generateSessionKey(): string {
		const slotContent = this._getSlottedElements.map(el => el.outerHTML).join('')
		return this.once ? hashContent(slotContent) : ''
	}
	/**
	 * Destroys the current TypeIt instance if it exists.
	 */
	private _destroyTypeIt() {
		if (this.typeItInstance) {
			try {
				this.typeItInstance.destroy()
			} catch (error) {
				console.error('Error destroying TypeIt instance:', error)
			}
			this.typeItInstance = null
		}
	}

	/**
	 * Processes a custom element for its typing behavior.
	 */
	private _processCustomElement(element: HTMLElement) {
		const action = element.getAttribute('action')
		const value = element.getAttribute('value')
		const cycle = element.getAttribute('cycle')

		// Handle cycle attribute - simple pipe-separated list
		if (cycle) {
			const items = cycle.split('|').map(item => item.trim())
			this._processCycle(items, element)
			return
		}

		switch (action) {
			case 'pause':
				this.typeItInstance?.pause(parseInt(value || '0', 10))
				break
			case 'delete':
				this.typeItInstance?.delete(parseInt(value || '0', 10))
				break
			default:
				if (element.tagName === 'P') {
					this.typeItInstance?.break()
				}
				// Treat as text if no action is defined
				this.typeItInstance?.type(element.textContent || '')
				break
		}
	}

	/**
	 * Processes cycling text with auto-calculated delete counts.
	 */
	private _processCycle(items: string[], element: HTMLElement) {
		if (items.length === 0) return

		const customPause = element.getAttribute('pause')
		const pauseDuration = customPause ? parseInt(customPause, 10) : this.cyclePause

		// Type each item with automatic deletion
		items.forEach((item, index) => {
			// Type the item
			this.typeItInstance?.type(item)

			// Pause after typing (except after last item when not looping)
			if (index < items.length - 1 || this.loop) {
				this.typeItInstance?.pause(pauseDuration)
			}

			// Delete back to start (except for last item when not looping)
			if (index < items.length - 1) {
				this.typeItInstance?.delete(item.length)
			} else if (this.loop) {
				// For looping, delete and start over
				this.typeItInstance?.delete(item.length)
			}
		})
	}

	/**
	 * Renders the component's HTML.
	 */
	render(): TemplateResult {
		return html`<div id="typewriter" aria-live="polite"></div>

			<div class="typewriter">
				<slot
					hidden
					@slotchange=${() => {
						this._startTyping()
					}}
				></slot>
			</div> `
	}
}

declare global {
	interface HTMLElementTagNameMap {
		'schmancy-typewriter': TypewriterElement
	}
}
